file.content:
var prevWeekIdx = -10;
monthLabels.forEach(function(m) {
    var offset = m.weekIndex * 12;
    if (m.weekIndex > prevWeekIdx + 3) {
        monthHtml += '<span style="position:absolute;left:' + offset + 'px">' + m.month + '</span>';
        prevWeekIdx = m.weekIndex;
    }
});
monthsEl.innerHTML = monthHtml;

// Render grid
var totalWeeks = weeks.length;
var edgeCount = 8;
var gridEl = document.getElementById('contrib-grid');
var gridHtml = '';

weeks.forEach(function(week, wi) {
    week.forEach(function(day, di) {
        if (day.future) {
            gridHtml += '<span class="contrib-cell" data-date="' + day.date + '" style="grid-column:' + (wi + 1) + ';grid-row:' + (di + 1) + '"></span>';
            return;
        }

        var hasRun = day.running > 0;
        var hasTok = day.tokens > 0;
        var runLvl = getRunLevel(day.running);
        var tokLvl = getTokenLevel(day.tokens);

        var bg;
        if (hasRun && hasTok) {
            bg = 'background:linear-gradient(90deg,var(--run-' + runLvl + ') 50%,var(--token-' + tokLvl + ') 50%)';
        } else if (hasRun) {
            bg = 'background:var(--run-' + runLvl + ')';
        } else if (hasTok) {
            bg = 'background:var(--token-' + tokLvl + ')';
        } else {
            bg = 'background:var(--empty-cell)';
        }

        var cls = 'contrib-cell';
        if (wi < edgeCount) cls += ' edge-left';
        if (wi >= totalWeeks - edgeCount) cls += ' edge-right';

        var runStr = (hasRun ? formatRunning(day.running) : '0') + ' km';
        var tokStr = hasTok ? formatTokens(day.tokens) : '0 M';
        var tooltip = day.date + '\n🏃 ' + runStr + '\n💻 ' + tokStr;

        gridHtml += '<span class="' + cls + '" data-date="' + day.date + '" data-tooltip="' + tooltip + '" style="' + bg + ';grid-column:' + (wi + 1) + ';grid-row:' + (di + 1) + '"></span>';
    });
});

