    btn.className = 'year-tab' + (y === activeYear ? ' active' : '');
    btn.onclick = function() {
        activeYear = y;
        var tabs = tabsEl.querySelectorAll('.year-tab');
        for (var i = 0; i < tabs.length; i++) tabs[i].classList.remove('active');
        btn.classList.add('active');
        renderList(y);
    };
    tabsEl.appendChild(btn);
});

function renderList(year) {
    var html = '';
    activityRecords.forEach(function(a) {
        if (a.date.slice(0, 4) !== year) return;
        var hour = a.start_time ? parseInt(a.start_time.split(':')[0], 10) : 12;
        var isTreadmill = a.type === 'treadmill_running';
        var period;
        if (hour >= 5 && hour < 9) period = '清晨';
        else if (hour >= 9 && hour < 12) period = '上午';
        else if (hour >= 12 && hour < 18) period = '下午';
        else period = '夜晚';
        var label = period + (isTreadmill ? '跑步机' : '户外');

        var dateDisplay = a.date + ' ' + (a.start_time || '00:00:00');

        html += '<tr>' +
            '<td class="text-left run-title">' + label + '</td>' +
            '<td class="text-right km-val">' + a.distance_km.toFixed(2) + '</td>' +
            '<td class="text-right">' + a.pace + '</td>' +
            '<td class="text-right">' + a.avg_hr + '</td>' +
            '<td class="text-right">' + a.duration + '</td>' +
            '<td class="text-right">' + dateDisplay + '</td>' +
            '</tr>';
    });
    listBody.innerHTML = html;
}

renderList(activeYear);

